import csv
from collections import Counter
c=Counter()
n=0
for r in csv.DictReader(open('/cases/Test1/analysis/evtx_all.csv', encoding='utf-8', errors='replace')):
    if r['Channel']=='Microsoft-Windows-WinRM/Operational' and r['EventId']=='145':
        n+=1
        # check payload for dest
        for k in ('PayloadData1','PayloadData2','PayloadData3','PayloadData4','PayloadData5','PayloadData6','Payload'):
            v=r.get(k,'') or ''
            if v and v.strip():
                # extract any URL
                if 'http' in v or 'wsman' in v or '://' in v or 'Address' in v:
                    c[v[:200]]+=1
                    break
print('WinRM145 examined',n,'unique payload prefixes:')
for k,v in c.most_common(15): print(v, k)
"

