bash -o pipefail -lc python3 -c "
import csv
# Look in evtx_security for 4624 to find SID->name mappings
seen={}
for r in csv.DictReader(open('/cases/Test1/analysis/evtx_security.csv', encoding='utf-8', errors='replace')):
    payload=r.get('Payload','') or ''
    # The Payload JSON has TargetUserName and TargetUserSid
    import re
    sm=re.search(r'"TargetUserSid","#text":"([^"]+)"', payload)
    nm=re.search(r'"TargetUserName","#text":"([^"]+)"', payload)
    if sm and nm:
        sid=sm.group(1); name=nm.group(1)
        if sid.startswith('S-1-5-21-3445421715') and sid not in seen:
            seen[sid]=name
for k,v in sorted(seen.items()): print(k, '=', v)
"

