bash -o pipefail -lc python3 -c "
import os, hashlib, csv, datetime
roots=['/cases/Test1/reports','/cases/Test1/analysis','/cases/Test1/exports','/cases/Test1/logs']
rows=[]
for root in roots:
    for dp,_,files in os.walk(root):
        for f in files:
            p=os.path.join(dp,f)
            try:
                st=os.stat(p)
                h=hashlib.sha256()
                with open(p,'rb') as fh:
                    for chunk in iter(lambda: fh.read(1<<20), b''): h.update(chunk)
                rows.append([p,'File',str(st.st_size),h.hexdigest(),datetime.datetime.utcfromtimestamp(st.st_ctime).strftime('%Y-%m-%dT%H:%M:%SZ'),'Output artefact'])
            except Exception as e:
                pass
with open('/cases/Test1/reports/artifact_manifest.csv','w',newline='') as f:
    w=csv.writer(f); w.writerow(['Path','Type','Size Bytes','SHA256','Created UTC','Purpose']); w.writerows(rows)
print('Manifest rows:',len(rows))
"
